-- Ejercicio: Estructuras de datos para un negocio de ventas-- Archivo: modulo2_unidad1_diseno.sql-- ==========================================-- 1. DEFINE LA TABLA DE CLIENTES-- ==========================================CREATE TABLE clientes (id_cliente INT, -- INT: Elegido porque los IDs son números enteros correlativos.nombre VARCHAR(100), -- VARCHAR(100): Texto de longitud variable, suficiente para nombres y apellidos.perfil_bio TEXT, -- TEXT: Ideal para almacenar descripciones o notas largas sin límite estricto de caracteres.fecha_registro DATE -- DATE: Guarda año, mes y día, que es lo único requerido para un registro.);-- ==========================================-- 2. DEFINE LA TABLA DE PRODUCTOS-- ==========================================CREATE TABLE productos (id_producto INT, -- INT: Número entero para identificar de forma única cada producto.descripcion VARCHAR(255), -- VARCHAR(255): Texto variable que permite una descripción detallada del artículo.precio DECIMAL(10,2), -- DECIMAL(10,2): Exactitud matemática necesaria para dinero (evita problemas de redondeo de FLOAT).esta_activo INT -- INT: completar con 1 si esta activo o con 0 si esta inactivo asi no ocupa mucho espacio.);